        // Iterate over all possible ending indices j (j >= i)
        for (let j = i; j < n; j++) {
            const numJ = nums[j];

            // Update the bitwise OR for the subarray nums[i...j]
            currentOr |= numJ;

            // Add the current element to the set of seen elements
            seenSet.add(numJ);

            // Check the condition for a "good" subarray:
            // The bitwise OR of the subarray must be equal to at least one element in the subarray.
            // Since currentOr is the OR of all elements, if it equals some element 'x' in the subarray, 
